    cashflow: '<path d="M3 17l5-5 4 3 6-7"/><path d="M5 20h14"/><path d="M18 5h3v3"/>',
    portfolio:'<path d="M4 19V9"/><path d="M10 19V5"/><path d="M16 19v-7"/><path d="M22 19H2"/>',
