function createInsightSignature(insight) {
  try {
    const base = `${insight.topic}|${insight.priority}|${insight.text}`;
    let hash = 0;
    for (let i = 0; i < base.length; i++) {
      hash = ((hash << 5) - hash) + base.charCodeAt(i);
      hash |= 0;
    }
    return hash.toString();
  } catch (_) {
    return null;
  }
}
