      currency:     baseCurrency || 'USD',
      granularity:  (result.meta && result.meta.granularity) || '1d',
      isSynthetic:  !!(result.meta && result.meta.isSynthetic),
      completeness: (result.meta && result.meta.completeness) || 1,
